import React from "react";
import styles from "./button-add.module.css";
import { useDispatch } from "react-redux";
import { addItem } from "../../app/cartSlice";

interface ButtonAddProps {
  id: number;
  text: string;
  imgSrc: string;
  title: string;
  price: number;
}

const ButtonAdd: React.FC<ButtonAddProps> = ({
  text,
  imgSrc,
  title,
  price,
}) => {
  const dispatch = useDispatch();
  const handleAddToCart = () => {
    dispatch(addItem({ id, name: title, price, img: imgSrc }));
  };

  return (
    <button className={styles.button_add} onClick={handleAddToCart}>
      <img
        src={`${process.env.PUBLIC_URL}/images/Cart-white.svg`}
        alt="cart-logo"
        width={24}
        height={24}
      />
      <span className={styles.button_text}>{text}</span>
    </button>
  );
};

export default ButtonAdd;

